// Login
// 登录
func (s *AuthServiceImpl) Login(ctx context.Context, req *login.LoginRequest) (*login.LoginResponse, error) {
	if req.GetCaptchaId() == "" || req.GetCaptchaCode() == "" {
		return nil, errors.New("验证码不存在")
	}
	if !captcha.Verify(req.GetCaptchaId(), req.GetCaptchaCode(), true) {
		return nil, errors.New("验证码错误")
	}

	user, err := s.baseUserCase.GetFromUserName(ctx, req.GetUserName())
	if err != nil {
		return nil, errors.New("用户不存在")
	}
	if user.Status != int32(common.Status_ENABLE) {
		return nil, errors.New("用户状态错误")
	}
	bMatched := crypto.CheckPasswordHash(req.GetPassword(), user.Password)
	if !bMatched {
		return nil, errors.New("密码错误")
	}

	// 查询角色信息
	var role *models.BaseRole
	role, err = s.baseRoleCase.GetFromID(ctx, user.RoleID)
	if err != nil {
		return nil, errors.New("角色不存在")
	}

	// 查询部门信息
	var dept *models.BaseDept
	dept, err = s.baseDeptCase.GetFromID(ctx, user.DeptID)
	if err != nil {
		return nil, errors.New("部门不存在")
	}

	// 生成访问令牌
	var accessToken, refreshToken string
	accessToken, refreshToken, err = s.UserToken.GenerateToken(&nmskitAuthData.UserTokenPayload{
		UserId:   user.ID,
		UserName: user.UserName,
		RoleId:   user.RoleID,
		RoleCode: role.Code,
		RoleName: role.Name,
		DeptId:   user.DeptID,
		DeptName: dept.Name,
	})
	if err != nil {
		return nil, errors.New("登录失败")
	}

	// Token 有效期
	expiresIn := s.UserToken.GetAccessTokenExpires()

	return &login.LoginResponse{
		TokenType:    engine.BearerWord,
		AccessToken:  accessToken,
		RefreshToken: refreshToken,
		ExpiresIn:    expiresIn,
	}, nil
}

// GetUserInfo
// 获取已经登录的用户的数据
func (s *AuthServiceImpl) GetUserInfo(ctx context.Context, req *emptypb.Empty) (*admin.UserInfo, error) {
	authInfo, err := authMiddleware.FromContext(ctx)
	if err != nil {
		log.Errorf("用户认证失败[%s]", err.Error())
		return nil, common.ErrorAccessForbidden("用户认证失败")
	}

	var baseUser *models.BaseUser
	baseUser, err = s.baseUserCase.GetFromID(ctx, authInfo.UserId)
	if err != nil {
		return nil, errors.New("用户不存在")
	}
	if baseUser.Status != int32(common.Status_ENABLE) {
		return nil, errors.New("用户状态错误")
	}

	// 查询角色信息
	var baseRole *models.BaseRole
	baseRole, err = s.baseRoleCase.GetFromID(ctx, baseUser.RoleID)
	if err != nil {
		return nil, errors.New("角色不存在")
	}

	condition := &data.BaseMenuCondition{
		Types:  []int32{int32(common.BaseMenuType_BUTTON)},
		Status: int32(common.Status_ENABLE),
	}
	//是否超级管理员
	if baseRole.Code != _const.BaseRoleCode_Super {
		condition.Ids = str.ConvertJsonStringToInt64Array(baseRole.Menus)
	}

	//用户权限
	baseMenus := make([]*models.BaseMenu, 0)
	baseMenus, err = s.baseMenuCase.List(ctx, condition)
	permission := make([]string, 0)
	if err != nil {
		return nil, common.ErrorAccessForbidden("用户权限不存在")
	}
	for _, item := range baseMenus {
		permission = append(permission, item.Path)
	}
	return &admin.UserInfo{
		UserName:   baseUser.UserName,
		NickName:   baseUser.NickName,
		Phone:      baseUser.Phone,
		Avatar:     baseUser.Avatar,
		Permission: permission,
		RoleCode:   baseRole.Code,
	}, nil
}

