// UpdateUserPwd
// 修改个人中心密码
func (s *AuthServiceImpl) UpdateUserPwd(ctx context.Context, req *admin.UpdatePwdForm) (*emptypb.Empty, error) {
	authInfo, err := authMiddleware.FromContext(ctx)
	if err != nil {
		log.Errorf("用户认证失败[%s]", err.Error())
		return nil, common.ErrorAccessForbidden("用户认证失败")
	}

	var baseUser *models.BaseUser
	baseUser, err = s.baseUserCase.GetFromID(ctx, authInfo.UserId)
	if err != nil {
		return nil, errors.New("用户不存在")
	}
	if req.GetNewPwd() != req.GetConfirmPwd() {
		return nil, errors.New("两次密码不一致")
	}
	bMatched := crypto.CheckPasswordHash(req.GetOldPwd(), baseUser.Password)
	if !bMatched {
		return nil, errors.New("旧密码错误")
	}

	password := s.baseUserCase.GetPassword(req.GetNewPwd())
	err = s.baseUserCase.UpdateByID(ctx, &models.BaseUser{
		ID:       authInfo.UserId,
		Password: password,
	})
	if err != nil {
		log.Error("UpdateUserPwd err:", err.Error())
		return nil, errors.New("重置密码失败")
	}
	return &emptypb.Empty{}, nil
}
